// AI usage and security events timeline visualization
let aiUsage = SigninLogs
| where TimeGenerated > {TimeRange:start}
| where AppDisplayName has_any ("AI", "Copilot", "chat", "gpt")
| summarize AIUsage = count() by bin(TimeGenerated, 1h)
| extend EventType = "AI使用";

let threats = SecurityAlert
| where TimeGenerated > {TimeRange:start}
| where AlertName has_any ("Jailbreak", "Prompt", "AI", "模型")
| summarize ThreatCount = count() by bin(TimeGenerated, 1h)
| extend EventType = "安全威胁";

// Combine data for the shared timeline view
aiUsage
| project TimeGenerated, Count = AIUsage, EventType
| union (
    threats
    | project TimeGenerated, Count = ThreatCount, EventType
)
| render timechart

// Correlation risk assessment summary - Real-time metrics from actual data
let totalThreats = toscalar(
    SecurityAlert
    | where TimeGenerated > {TimeRange:start}
    | where AlertName has_any ("Jailbreak", "Prompt", "AI", "模型")
    | summarize count()
);

let totalUsage = toscalar(
    SigninLogs
    | where TimeGenerated > {TimeRange:start}
    | where AppDisplayName has_any ("AI", "Copilot", "chat", "gpt")
    | summarize count()
);

let uniqueUsers = toscalar(
    SigninLogs
    | where TimeGenerated > {TimeRange:start}
    | where AppDisplayName has_any ("AI", "Copilot", "chat", "gpt")
    | summarize dcount(UserPrincipalName)
);

let correlatedEvents = toscalar(
    SigninLogs
    | where TimeGenerated > {TimeRange:start}
    | where AppDisplayName has_any ("AI", "Copilot", "chat", "gpt")
    | extend UsageHour = bin(TimeGenerated, 1h)
    | join kind=inner (
        SecurityAlert
        | where TimeGenerated > {TimeRange:start}
        | where AlertName has_any ("Jailbreak", "Prompt", "AI", "模型")
        | extend ThreatHour = bin(TimeGenerated, 1h)
    ) on $left.UsageHour == $right.ThreatHour
    | summarize dcount(UsageHour)
);

let riskRatio = case(totalUsage > 0, round(todouble(totalThreats) / todouble(totalUsage) * 100, 2), 0.0);

let riskLevel = case(
    riskRatio > 5, "🔥 高风险",
    riskRatio > 2, "🟠 中等风险",
    "🟢 低风险"
);

// Create table using union of print statements
print Metric = "📊 AI使用总量", Value = tostring(totalUsage), Description = "所选时间段内AI应用登录数量"
| union (print Metric = "⚠️ 安全威胁总数", Value = tostring(totalThreats), Description = "AI-related security alerts detected in the same window")
| union (print Metric = "👥 活跃用户", Value = tostring(uniqueUsers), Description = "与AI应用交互的独立用户")
| union (print Metric = "🔗 关联时间窗口", Value = tostring(correlatedEvents), Description = "使用量和威胁重叠的小时时段")
| union (print Metric = "📈 风险比率", Value = strcat(tostring(riskRatio), "%"), Description = "威胁数量占AI总使用量的百分比")
| union (print Metric = "🎯 整体风险级别", Value = riskLevel, Description = "基于关联统计的风险态势")

// AI incident response efficiency KPIs with safe fallback (no SecurityIncident table => diagnostic rows)
let incidents = union isfuzzy=true
(
    SecurityIncident
    | where TimeGenerated > {TimeRange:start}
    | where isnotempty(CreatedTime)
    | extend ClosedAt = todatetime(ClosedTime)
    | extend IsResolved = iif(Status in ('Closed', 'Resolved', '已解决', '已关闭') or isnotempty(ClosedAt), 1, 0)
    | extend ResponseHours = iif(isnotempty(ClosedAt), datetime_diff('minute', ClosedAt, CreatedTime) / 60.0, real(null))
    | project CreatedTime, ClosedAt, IsResolved, ResponseHours
),
(
    datatable(CreatedTime:datetime, ClosedAt:datetime, IsResolved:long, ResponseHours:real)[]
);
let totalEvents = toscalar(incidents | summarize c = count());
let resolvedEvents = toscalar(incidents | summarize c = countif(IsResolved == 1));
let resolutionRate = iff(totalEvents > 0, round(todouble(resolvedEvents) / todouble(totalEvents) * 100.0, 1), real(null));
let avgResp = toscalar(incidents | where isnotempty(ResponseHours) | summarize v = round(avg(ResponseHours), 2));
let p50Resp = toscalar(incidents | where isnotempty(ResponseHours) | summarize v = round(percentile(ResponseHours, 50), 2));
let maxResp = toscalar(incidents | where isnotempty(ResponseHours) | summarize v = round(max(ResponseHours), 2));
let hasRows = totalEvents > 0;
union
(
    print Metric=' 事件总数', Value=iff(hasRows, tostring(totalEvents), 'N/A'), Description=iff(hasRows, '来自 SecurityIncident', '数据源检查：需要SecurityIncident表/权限')
),
(
    print Metric=' 已解决事件', Value=iff(hasRows, tostring(resolvedEvents), 'N/A'), Description=iff(hasRows, '状态为Closed/Resolved或存在ClosedTime', '数据源检查：需要SecurityIncident表/权限')
),
(
    print Metric=' 解决率', Value=iff(hasRows, strcat(tostring(resolutionRate), '%'), 'N/A'), Description=iff(hasRows, '已解决事件/总事件', '数据源检查：需要SecurityIncident表/权限')
),
(
    print Metric=' 平均响应时间', Value=iff(hasRows and isnotempty(avgResp), strcat(tostring(avgResp), 'h'), 'N/A'), Description=iff(hasRows, 'ClosedTime - CreatedTime', '数据源检查：需要Created/Closed时间戳')
),
(
    print Metric=' 中位响应时间', Value=iff(hasRows and isnotempty(p50Resp), strcat(tostring(p50Resp), 'h'), 'N/A'), Description=iff(hasRows, 'P50(ClosedTime - CreatedTime)', '数据源检查：需要Created/Closed时间戳')
),
(
    print Metric=' 最长响应时间', Value=iff(hasRows and isnotempty(maxResp), strcat(tostring(maxResp), 'h'), 'N/A'), Description=iff(hasRows, 'Max(ClosedTime - CreatedTime)', '数据源检查：需要Created/Closed时间戳')
)

// AI Data Governance Compliance Score - Real-time metrics from actual data
let totalAILogins = toscalar(
    SigninLogs
    | where TimeGenerated > ago(30d)
    | where AppDisplayName has_any ("AI", "Copilot", "chat", "gpt")
    | summarize count()
);

let complianceLogins = toscalar(
    SigninLogs
    | where TimeGenerated > ago(30d)
    | where AppDisplayName has_any ("Security Copilot", "Azure AI Studio", "Microsoft 365 Copilot")
    | summarize count()
);

let violationLogins = toscalar(
    SigninLogs
    | where TimeGenerated > ago(30d)
    | where AppDisplayName has_any ("ChatGPT", "Claude", "Google Bard")
    | summarize count()
);

let dataLeakAlerts = toscalar(
    SecurityAlert
    | where TimeGenerated > ago(30d)
    | where AlertName has_any ("DLP", "数据", "泄露") and Description has_any ("AI", "Copilot")
    | summarize count()
);

let complianceRate = case(totalAILogins > 0, round(todouble(complianceLogins) / todouble(totalAILogins) * 100, 1), 0.0);
let violationRate = case(totalAILogins > 0, round(todouble(violationLogins) / todouble(totalAILogins) * 100, 1), 0.0);
let dataRiskScore = case(
    dataLeakAlerts >= 10, 90,
    dataLeakAlerts >= 5, 70,
    dataLeakAlerts >= 1, 50,
    20
);
let overallRisk = case(
    violationRate > 30 or dataRiskScore >= 70, "🔥 高风险",
    violationRate > 15 or dataRiskScore >= 50, "🟠 中风险", 
    violationRate > 5, "🟡 需关注",
    "🟢 低风险"
);

// Create table using union of print statements
print Metric = "✅ AI使用合规率", Value = strcat(tostring(complianceRate), "%"), Description = "AI应用合规使用率百分比"
| union (print Metric = "⚠️ AI违规率", Value = strcat(tostring(violationRate), "%"), Description = "AI应用受限使用率百分比")
| union (print Metric = "📊 数据风险评分", Value = tostring(dataRiskScore), Description = "基于数据泄露告警的风险评分")
| union (print Metric = "🎯 整体风险级别", Value = overallRisk, Description = "全面数据治理风险评估")
